-- ============================================
-- Legislacao full-site: daniel-vilela / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/144523
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = daniel-vilela-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 86
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=144523, tipo Deputado(a), ordemAssinatura=1.
-- 14 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'daniel-vilela';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'daniel-vilela: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao daniel-vilela: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2179012', '2186153', '2186151', '2184079', '2183985', '2182649', '2182555', '2182173', '2182172', '2182168', '2182100', '2182099', '2181903', '2181562', '2181560', '2181261', '2180871', '2179011', '2173937', '2173672', '2170904', '2165107', '2158616', '2158611', '2156585', '2156579', '2155168', '2151806', '2151194', '2148133', '2145160', '2178995', '2173936', '2173671', '2170902', '2162601', '2158615', '2156584', '2155205', '2151820', '2151803', '2151192', '2147916', '2173753', '2173143', '2170200', '2162592', '2158614', '2156583', '2155204', '2151818', '2151464', '2151191', '2146265', '2173752', '2173141', '2168816', '2162276', '2158613', '2156582', '2155203', '2151814', '2151196', '2148694', '2146264', '2170906', '2166751', '2160954', '2158612', '2156580', '2155169', '2151807', '2146262', '2181892', '2174975', '2188726', '2178993', '2173751', '2189073', '2188620', '2178994', '2158609', '2158608', '2151195', '2158610', '2158607');
  IF target_present <> 86 THEN
    RAISE EXCEPTION 'Pre-condicao daniel-vilela: esperadas 86 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2179012', '2186153', '2186151', '2184079', '2183985', '2182649', '2182555', '2182173', '2182172', '2182168', '2182100', '2182099', '2181903', '2181562', '2181560', '2181261', '2180871', '2179011', '2173937', '2173672', '2170904', '2165107', '2158616', '2158611', '2156585', '2156579', '2155168', '2151806', '2151194', '2148133', '2145160', '2178995', '2173936', '2173671', '2170902', '2162601', '2158615', '2156584', '2155205', '2151820', '2151803', '2151192', '2147916', '2173753', '2173143', '2170200', '2162592', '2158614', '2156583', '2155204', '2151818', '2151464', '2151191', '2146265', '2173752', '2173141', '2168816', '2162276', '2158613', '2156582', '2155203', '2151814', '2151196', '2148694', '2146264', '2170906', '2166751', '2160954', '2158612', '2156580', '2155169', '2151807', '2146262', '2181892', '2174975', '2188726', '2178993', '2173751', '2189073', '2188620', '2178994', '2158609', '2158608', '2151195', '2158610', '2158607')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'daniel-vilela-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao daniel-vilela: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao daniel-vilela: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

